// Extract parameters from webhook body
const body = $input.first().json.body || {};
const personaId = body.persona_id || null;
const shouldImprove = body.improve !== false;

return [
  {
    json: {
      persona_id: personaId,
      should_improve: shouldImprove,
      started_at: new Date().toISOString()
    }
  }
];

// Extract the call_id printed by run_call.py
const stdout = $input.first().json.stdout || '';
const match = stdout.match(/CALL_ID:([\w_]+)/);
if (!match) throw new Error('Could not find CALL_ID in output: ' + stdout);
const callId = match[1];
console.log('Extracted call_id:', callId);
return [{ json: { call_id: callId, call_output: stdout } }];

// Merge outputs and build response summary
const callOutput = $('Loop 1 — Run Call').first().json.stdout || '';
const analyzeOutput = $('Loop 2 — Analyze Call').first().json.stdout || '';
const improveOutput = $input.first().json.stdout || 'Improvement skipped';

const scoreMatch = analyzeOutput.match(/Score: (\d+)/);
const outcomeMatch = analyzeOutput.match(/Outcome: ([\w_]+)/);
const insightMatch = analyzeOutput.match(/Key insight: (.+)/);
const callIdMatch = callOutput.match(/CALL_ID:([\w_]+)/);

return [{
  json: {
    status: 'complete',
    call_id: callIdMatch ? callIdMatch[1] : 'unknown',
    score: scoreMatch ? parseInt(scoreMatch[1]) : null,
    outcome: outcomeMatch ? outcomeMatch[1] : 'unknown',
    key_insight: insightMatch ? insightMatch[1].trim() : null,
    improved: true,
    completed_at: new Date().toISOString()
  }
}];

